import React from "react";
import { GeneralContext } from "./GeneralContext";
// Assuming you have a mock data file for your watchlist stocks
import { watchlist } from "../data/data";

// 1. Separate component for each individual row in the Watchlist
const WatchListElement = ({ stock }) => {
  const { handleOpenBuyWindow } = useContext(GeneralContext);

  return (
    <li>
      <div className="item">
        {/* Stock name on the left side */}
        <p className={stock.isUp ? "up" : "down"}>{stock.name}</p>

        {/* Percentage change and Price aligned on the right side */}
        <div className="item-info">
          <span className="percent">{stock.percent}</span>
          <span className="price">{stock.price}</span>
        </div>
      </div>

      {/* Action overlay buttons that match our fixed index.css hover trigger */}
      <div className="actions">
        <button className="buy" onClick={() => handleOpenBuyWindow(stock.name)}>
          Buy
        </button>
        <button className="sell">Sell</button>
      </div>
    </li>
  );
};

// 2. Main WatchList wrapper component
const WatchList = () => {
  return (
    <div className="watchlist-container">
      {/* Top Search bar inside the watchlist panel */}
      <div className="search-container">
        <input
          type="text"
          name="search"
          id="search"
          placeholder="Search eg: infy, bse, nifty fut weekly, gold mcx"
          className="search"
        />
        <span className="counts"> {watchlist.length} / 50</span>
      </div>

      {/* Map over the actual stock array dynamically */}
      <ul className="list">
        {watchlist.map((stock, index) => {
          return <WatchListElement stock={stock} key={index} />;
        })}
      </ul>
    </div>
  );
};

export default WatchList;
